package com.tzesh.springtemplate.service.auth;

import io.jsonwebtoken.Claims;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.io.Decoders;
import io.jsonwebtoken.security.Keys;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.stereotype.Service;

import javax.crypto.SecretKey;
import java.util.Date;
import java.util.HashMap;
import java.util.Map;
import java.util.function.Function;

/**
 * JWT Service class for generating and validating JWT tokens
 *
 * @author tzesh
 * @see io.jsonwebtoken.JwtParser
 * @see io.jsonwebtoken.JwtBuilder
 * @see io.jsonwebtoken.Jwts
 */
@Service
public class JwtService {
    @Value("${security.jwt.secret-key}")
    private String secretKey;
    @Value("${security.jwt.expiration}")
    private long jwtExpiration;
    @Value("${security.jwt.refresh-expiration}")
    private long refreshExpiration;
    @Value("${security.jwt.issuer}")
    private String issuer;

    /**
     * Get signing key - username
     *
     * @param token JWT token
     * @return Key
     */
    public String extractUsername(final String token) {
        return extractClaim(token, Claims::getSubject);
    }

    /**
     * Extract claims from token
     *
     * @param token          JWT token
     * @param claimsResolver Claims resolver
     * @param <T>
     * @return T
     */
    public <T> T extractClaim(final String token, final Function<Claims, T> claimsResolver) {
        final Claims claims = extractAllClaims(token);
        return claimsResolver.apply(claims);
    }

    /**
     * Get signing key
     *
     * @param userDetails UserDetails
     * @return Key
     */
    public String generateToken(final UserDetails userDetails) {
        return generateToken(new HashMap<>(), userDetails);
    }

    /**
     * Generate JWT token
     *
     * @param extraClaims extra claims
     * @param userDetails UserDetails
     * @return String
     */
    public String generateToken(final Map<String, Object> extraClaims, final UserDetails userDetails) {
        return buildToken(extraClaims, userDetails, jwtExpiration);
    }

    /**
     * Generate refresh token
     *
     * @param userDetails UserDetails
     * @return String
     */
    public String generateRefreshToken(final UserDetails userDetails) {
        return buildToken(new HashMap<>(), userDetails, refreshExpiration);
    }

    /**
     * check if token is valid
     *
     * @param token       JWT token
     * @param userDetails UserDetails
     * @return boolean
     */
    public boolean isTokenValid(final String token, final UserDetails userDetails) {
        final String username = extractUsername(token);
        return (username.equals(userDetails.getUsername())) && !isTokenExpired(token);
    }

    /**
     * Build JWT token
     *
     * @param extraClaims extra claims
     * @param userDetails UserDetails
     * @param expiration  expiration time
     * @return
     */
    private String buildToken(final Map<String, Object> extraClaims, final UserDetails userDetails, final long expiration) {
        return Jwts
                .builder()
                .claims(extraClaims)
                .subject(userDetails.getUsername())
                .issuedAt(new Date(System.currentTimeMillis()))
                .expiration(new Date(System.currentTimeMillis() + expiration))
                .issuer(issuer)
                .signWith(getSignInKey())
                .compact();
    }

    /**
     * Check if token is expired
     *
     * @param token JWT token
     * @return boolean
     */
    private boolean isTokenExpired(final String token) {
        return extractExpiration(token).before(new Date());
    }

    /**
     * Extract expiration date from token
     *
     * @param token JWT token
     * @return Date
     */
    private Date extractExpiration(final String token) {
        return extractClaim(token, Claims::getExpiration);
    }

    /**
     * Extract all claims from token
     *
     * @param token JWT token
     * @return Claims
     */
    private Claims extractAllClaims(final String token) {
        return Jwts
                .parser()
                .verifyWith(getSignInKey())
                .build()
                .parseSignedClaims(token)
                .getPayload();
    }

    /**
     * Get signing key from secret key
     *
     * @return Key
     */
    private SecretKey getSignInKey() {
        byte[] keyBytes = Decoders.BASE64.decode(secretKey);
        return Keys.hmacShaKeyFor(keyBytes);
    }
}

package com.tzesh.springtemplate.service.auth;

import com.tzesh.springtemplate.repository.auth.TokenRepository;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import lombok.RequiredArgsConstructor;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.web.authentication.logout.LogoutHandler;
import org.springframework.stereotype.Service;

/**
 * Logout service to revoke token
 *
 * @author tzesh
 * @see LogoutHandler
 * @see TokenRepository
 */
@Service
@RequiredArgsConstructor
public class LogoutService implements LogoutHandler {

    private final TokenRepository tokenRepository;

    /**
     * Revoke token
     *
     * @param request        Request
     * @param response       Response
     * @param authentication Authentication
     */
    @Override
    public void logout(
            final HttpServletRequest request,
            final HttpServletResponse response,
            final Authentication authentication) {
        final String authHeader = request.getHeader("Authorization");
        final String jwt;

        if (authHeader == null || !authHeader.startsWith("Bearer ")) {
            return;
        }

        jwt = authHeader.substring(7);

        final var storedToken = tokenRepository.findByToken(jwt)
                .orElse(null);

        if (storedToken != null) {
            storedToken.setExpired(true);
            storedToken.setRevoked(true);

            tokenRepository.save(storedToken);

            SecurityContextHolder.clearContext();
        }
    }
}

package com.tzesh.springtemplate.controller.auth;

import com.tzesh.springtemplate.base.response.BaseResponse;
import com.tzesh.springtemplate.response.AuthenticationResponse;
import com.tzesh.springtemplate.request.auth.AuthorizationRequest;
import com.tzesh.springtemplate.request.auth.LoginRequest;
import com.tzesh.springtemplate.request.auth.RegisterRequest;
import com.tzesh.springtemplate.service.auth.AuthenticationService;
import com.tzesh.springtemplate.base.annotation.Idempotent;
import com.tzesh.springtemplate.base.annotation.RateLimitCategory;
import com.tzesh.springtemplate.base.annotation.RateLimitCategoryType;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.springframework.http.ResponseEntity;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.validation.annotation.Validated;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.io.IOException;
import java.util.concurrent.TimeUnit;

/**
 * @author tzesh
 */
@RestController
@RequestMapping("/auth")
@RequiredArgsConstructor
@Validated
@Tag(name = "Authentication Controller", description = "Authentication operations for users")
@RateLimitCategory(RateLimitCategoryType.AUTHENTICATION)
public class AuthenticationController {

    private final AuthenticationService authenticationService;

    @PostMapping("/register")
    @Operation(summary = "Register a new user", description = "Register a new user with the given details and return the authentication response")
    @Idempotent(ttl = 1, timeUnit = TimeUnit.HOURS)
    public ResponseEntity<BaseResponse<AuthenticationResponse>> register(@RequestBody @Valid RegisterRequest request) {
        // call the register method in the authentication service
        AuthenticationResponse response = authenticationService.register(request);

        // return the response
        return BaseResponse.created(response).message("User registered successfully").build();
    }
    @PostMapping("/login")
    @Operation(summary = "Login a user", description = "Login a user with the given details and return the authentication response")
    public ResponseEntity<BaseResponse<AuthenticationResponse>> login(@RequestBody @Valid LoginRequest request) {
        // call the login method in the authentication service
        AuthenticationResponse response = authenticationService.login(request);

        // return the response
        return BaseResponse.ok(response).message("User logged in successfully").build();
    }

    @PostMapping("/refresh-token")
    @Operation(summary = "Refresh the authentication token", description = "Refresh the authentication token and return the authentication response")
    public ResponseEntity<BaseResponse<AuthenticationResponse>> refreshToken(HttpServletRequest request, HttpServletResponse response) throws IOException {
        // call the refresh token method in the authentication service
        AuthenticationResponse refreshToken = authenticationService.refreshToken(request, response);

        // return the response
        return BaseResponse.ok(refreshToken).message("Token refreshed successfully").build();
    }

    @PostMapping("/authorize")
    @PreAuthorize("hasRole('ADMIN') || hasRole('USER') || hasRole('MODERATOR')")
    @Operation(summary = "Authorize the user", description = "Authorize the user and return the authentication response")
    public ResponseEntity<BaseResponse<AuthenticationResponse>> authorize(@RequestBody @Valid AuthorizationRequest request) {
        // call the login method in the authentication service
        AuthenticationResponse response = authenticationService.authorize(request);

        // return the response
        return BaseResponse.ok(response).message("User authorized successfully").build();
    }
}

package com.tzesh.springtemplate.service.auth;

import com.tzesh.springtemplate.base.entity.field.BaseAuditableFields;
import com.tzesh.springtemplate.base.error.GenericErrorMessage;
import com.tzesh.springtemplate.base.exception.BaseException;
import com.tzesh.springtemplate.base.exception.NotFoundException;
import com.tzesh.springtemplate.entity.User;
import com.tzesh.springtemplate.entity.auth.TokenEntity;
import com.tzesh.springtemplate.enumeration.auth.Role;
import com.tzesh.springtemplate.enumeration.auth.Token;
import com.tzesh.springtemplate.repository.auth.TokenRepository;
import com.tzesh.springtemplate.repository.user.UserRepository;
import com.tzesh.springtemplate.request.auth.AuthorizationRequest;
import com.tzesh.springtemplate.request.auth.LoginRequest;
import com.tzesh.springtemplate.request.auth.RegisterRequest;
import com.tzesh.springtemplate.response.AuthenticationResponse;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import lombok.RequiredArgsConstructor;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.HttpHeaders;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;
import java.util.List;

/**
 * Authentication service for login and register
 *
 * @author tzesh
 * @see AuthenticationService
 * @see AuthenticationManager
 * @see PasswordEncoder
 * @see JwtService
 * @see UserRepository
 * @see TokenRepository
 */
@Service
@RequiredArgsConstructor
public class AuthenticationService {
    @Value("${security.jwt.authorization-key}")
    private String authorizationKey;
    private final UserRepository repository;
    private final TokenRepository tokenRepository;
    private final PasswordEncoder passwordEncoder;
    private final JwtService jwtService;
    private final AuthenticationManager authenticationManager;

    /**
     * Register user
     *
     * @param request Register request
     * @return AuthenticationResponse
     * @throws RuntimeException if username or email already exists
     * @see RegisterRequest
     */
    public AuthenticationResponse register(final RegisterRequest request) {
        if (repository.existsByUsernameOrEmail(request.username(), request.email())) {
            throw new BaseException(
                    GenericErrorMessage.builder()
                            .message("Username or email already exists")
                            .build()
            );
        }

        final User user = User.builder()
                .username(request.username())
                .email(request.email())
                .name(request.name())
                .password(passwordEncoder.encode(request.password()))
                .role(Role.USER)
                .build();
        final BaseAuditableFields auditableFields = new BaseAuditableFields();
        auditableFields.setCreatedBy(user.getUsername());
        auditableFields.setCreatedDate(LocalDateTime.now());
        user.setAuditableFields(auditableFields);

        final User savedUser = repository.save(user);
        final String jwtToken = jwtService.generateToken(user);
        final String refreshToken = jwtService.generateRefreshToken(user);

        saveUserToken(savedUser, jwtToken);

        return AuthenticationResponse.builder()
                .accessToken(jwtToken)
                .refreshToken(refreshToken)
                .build();
    }

    /**
     * Login user
     *
     * @param request Login request
     * @return AuthenticationResponse
     * @see LoginRequest
     */
    public AuthenticationResponse login(final LoginRequest request) {
        authenticationManager.authenticate(
                new UsernamePasswordAuthenticationToken(
                        request.username(),
                        request.password()
                )
        );

        final User user = repository.findByUsername(request.username())
                .orElseThrow(
                        () -> new NotFoundException(
                                GenericErrorMessage.builder()
                                        .message("User not found with username: " + request.username())
                                        .build()
                        )
                );

        final String jwtToken = jwtService.generateToken(user);
        final String refreshToken = jwtService.generateRefreshToken(user);
        revokeAllUserTokens(user);
        saveUserToken(user, jwtToken);
        return AuthenticationResponse.builder()
                .accessToken(jwtToken)
                .refreshToken(refreshToken)
                .build();
    }

    /**
     * Save user token
     *
     * @param user     User
     * @param jwtToken JWT token
     */
    private void saveUserToken(final User user, final String jwtToken) {
        final TokenEntity tokenEntity = TokenEntity.builder()
                .user(user)
                .token(jwtToken)
                .expired(false)
                .revoked(false)
                .build();
        tokenRepository.save(tokenEntity);
    }

    /**
     * Revoke all user tokens
     *
     * @param user User
     */
    private void revokeAllUserTokens(final User user) {
        final List<TokenEntity> validUserTokenEntities = tokenRepository.findAllValidTokenByUser(user.getId());
        if (validUserTokenEntities.isEmpty())
            return;
        validUserTokenEntities.forEach(tokenEntity -> {
            tokenEntity.setExpired(true);
            tokenEntity.setRevoked(true);
        });
        tokenRepository.saveAll(validUserTokenEntities);
    }

    /**
     * Refresh token
     *
     * @param request  HTTP request
     * @param response HTTP response
     */
    public AuthenticationResponse refreshToken(final HttpServletRequest request, final HttpServletResponse response) {
        final String authHeader = request.getHeader(HttpHeaders.AUTHORIZATION);
        final String refreshToken;
        final String username;
        if (authHeader == null || !authHeader.startsWith("Bearer ")) {
            return null;
        }
        refreshToken = authHeader.substring(7);
        username = jwtService.extractUsername(refreshToken);
        if (username != null) {
            final User user = this.repository.findByUsername(username)
                    .orElseThrow(
                            () -> new NotFoundException(
                                    GenericErrorMessage.builder()
                                            .message("User not found with username: " + username)
                                            .build()
                            )
                    );
            if (jwtService.isTokenValid(refreshToken, user)) {
                final String accessToken = jwtService.generateToken(user);
                revokeAllUserTokens(user);
                saveUserToken(user, accessToken);
                return AuthenticationResponse.builder()
                        .accessToken(accessToken)
                        .refreshToken(refreshToken)
                        .build();
            }
        }
        return null;
    }

    /**
     * Authorize user to the role
     *
     * @param request Authorization request
     * @return AuthenticationResponse
     * @see AuthorizationRequest
     * @see AuthenticationResponse
     */
    public AuthenticationResponse authorize(final AuthorizationRequest request) {
        if (!request.secret().equals(authorizationKey)) {
            throw new RuntimeException("Secret is not correct");
        }

        final User user = repository.findByUsername(request.username())
                .orElseThrow(
                        () -> new NotFoundException(
                                GenericErrorMessage.builder()
                                        .message("User not found with username: " + request.username())
                                        .build()
                        )
                );
        user.setRole(request.role());

        final BaseAuditableFields auditableFields = user.getAuditableFields();
        auditableFields.setUpdatedBy("SYSTEM");
        auditableFields.setUpdatedDate(LocalDateTime.now());

        final User updatedUser = repository.save(user);
        final String jwtToken = jwtService.generateToken(updatedUser);
        final String refreshToken = jwtService.generateRefreshToken(updatedUser);
        saveUserToken(updatedUser, jwtToken);
        return AuthenticationResponse.builder()
                .accessToken(jwtToken)
                .refreshToken(refreshToken)
                .build();
    }

}

package com.tzesh.springtemplate.entity;

import com.tzesh.springtemplate.entity.auth.TokenEntity;
